import type { SamplePack, SampleCategory, SampleInfo } from '@typedefs/samplePack';
import { normalizeUrl } from '@utils/urlUtils';

const BASE = 'data/samples/packs/fairlight-cmi';

function cmiSample(file: string, origCat: string, displayCat: SampleCategory): SampleInfo {
  const name = file.replace(/\.wav$/i, '');
  return {
    filename: file,
    name,
    category: displayCat,
    url: normalizeUrl(`${BASE}/${origCat}/${encodeURIComponent(file)}`),
  };
}

